INSERT INTO `v1_7e9880395bf505ec6945d11fcfdd885f042293898a633bb5103d2cb3a8c1c984` VALUES (11601, "ツムギ・オンステージ！ツムギがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", 0.625, 1, 6, 0.75, "ツムギのボトルキャップ");
INSERT INTO `v1_7e9880395bf505ec6945d11fcfdd885f042293898a633bb5103d2cb3a8c1c984` VALUES (11602, "サマー衣装のツムギが、キャップでオンステージ！涼しげな衣装を\nまとい、熱いステージを繰り広げた彼女の勇姿を思い出すことがで\nきる。", 0.625, 1, 6, 0.75, "ツムギのサマーボトルキャップ");
